import { Component, OnInit } from '@angular/core';
import { NavigationStart, Router } from '@angular/router';
import {Nav} from './navbar.interface';


@Component({
  selector: 'app-navbar',
  templateUrl: './navbar.component.html',
  styleUrls: ['./navbar.component.scss']
})
export class NavbarComponent implements OnInit {

  active : string = '';
  isOpen : boolean= false;

  menu: Nav []= [
    { route: '/', title: ' בית', icon: 'home' },
    { route: '/login', title: 'Login', icon: 'login'},
    { route: '/signup', title: 'Sign Up', icon: 'signup'},
    { route: '/customers', title: 'Customers', icon: 'customr'},
    { route: '/contacts', title: 'Contacts', icon: 'contact'},

  ];
  sidebar: Nav[] = [
    ...this.menu,


];


  constructor(router: Router) {

    router.events.subscribe(ev => {
        if (ev instanceof NavigationStart) {
            this.active = ev.url;
            this.isOpen= false;
        }
    });

}



  ngOnInit() {}
}
